<script>
(() => {
const csrf=document.querySelector('meta[name="csrf-token"]').content;
const generateUrl={{ Illuminate\Support\Js::from(route('cms.screenshots.generate')) }},saveUrl={{ Illuminate\Support\Js::from(route('cms.screenshots.save')) }},referenceUrl={{ Illuminate\Support\Js::from(route('cms.screenshots.references.store')) }},assetDeleteBase={{ Illuminate\Support\Js::from(url('/cms/screenshot-maker/references')) }};
const fonts={bebas:'Bebas Neue',outfit:'Outfit',amatic:'Amatic SC'},weights={bebas:'400',outfit:'900',amatic:'700'},colors={white:'#ffffff',yellow:'#facc15',black:'#080808'};
const jsonError=async response=>{const payload=await response.json().catch(()=>({}));throw new Error(payload.message||Object.values(payload.errors||{})[0]?.[0]||'Request failed.')};
const bindDelete=item=>item.querySelector('button').addEventListener('click',async()=>{if(!confirm('Delete this saved reference?'))return;const response=await fetch(`${assetDeleteBase}/${encodeURIComponent(item.dataset.name)}`,{method:'DELETE',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf}});if(!response.ok)return jsonError(response);item.remove()});
document.querySelectorAll('.reference-item').forEach(bindDelete);
document.getElementById('referenceForm').addEventListener('submit',async event=>{event.preventDefault();const button=event.currentTarget.querySelector('button'),label=button.textContent;button.disabled=true;button.textContent='Saving…';try{const response=await fetch(referenceUrl,{method:'POST',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf},body:new FormData(event.currentTarget)});if(!response.ok)return await jsonError(response);const payload=await response.json();payload.references.forEach(reference=>{const item=document.createElement('div');item.className='reference-item';item.dataset.name=reference.name;item.innerHTML=`<img src="${reference.url}" alt="App Store style reference"><button type="button" title="Delete">×</button>`;document.getElementById('referenceList').append(item);bindDelete(item)});event.currentTarget.reset()}catch(error){alert(error.message)}finally{button.disabled=false;button.textContent=label}});
function wrapLines(ctx,text,maxWidth){const words=[];for(const raw of String(text||'').trim().split(/\s+/).filter(Boolean)){if(ctx.measureText(raw).width<=maxWidth){words.push(raw);continue}let part='';for(const char of raw){if(part&&ctx.measureText(part+char).width>maxWidth){words.push(part);part=char}else part+=char}if(part)words.push(part)}const lines=[];let line='';for(const word of words){const candidate=line?`${line} ${word}`:word;if(!line||ctx.measureText(candidate).width<=maxWidth){line=candidate}else{lines.push(line);line=word}}if(line)lines.push(line);return lines}
function fitBlock(ctx,text,maxWidth,maxLines,startSize,minSize,family,weight){let size=startSize,lines=[];while(size>=minSize){ctx.font=`${weight} ${size}px "${family}"`;lines=wrapLines(ctx,text,maxWidth);if(lines.length<=maxLines)return{size,lines};size-=3}ctx.font=`${weight} ${minSize}px "${family}"`;return{size:minSize,lines:wrapLines(ctx,text,maxWidth)}}
function sectionValues(section){const form=section.querySelector('.shot-form'),data=Object.fromEntries([...new FormData(form)].filter(([,value])=>typeof value==='string'));return data}
function syncPreview(section){const values=sectionValues(section),artboard=section.querySelector('.shot-artboard'),headline=section.querySelector('.shot-headline'),support=section.querySelector('.shot-supporting');artboard.dataset.position=values.text_position;headline.textContent=values.headline;support.textContent=values.supporting_text;headline.className=`shot-headline font-${values.headline_font} color-${values.headline_color}`;support.className=`shot-supporting font-${values.supporting_font} color-${values.supporting_color}`;headline.style.fontSize=`${Math.max(6.4,Math.min(11,600/Math.max(1,values.headline.length)))}cqw`;support.style.fontSize=`${Math.max(3.1,Math.min(5.1,620/Math.max(1,values.supporting_text.length)))}cqw`}
function loadImage(url){return new Promise((resolve,reject)=>{const image=new Image();image.onload=()=>resolve(image);image.onerror=()=>reject(new Error('Generated artwork could not be loaded.'));image.src=url})}
async function compose(section){const values=sectionValues(section),url=section.dataset.artworkUrl;if(!url)throw new Error('Generate artwork first.');await Promise.all(Object.values(fonts).map(font=>document.fonts.load(`100px "${font}"`)));const image=await loadImage(url),canvas=document.createElement('canvas');canvas.width=1290;canvas.height=2796;const ctx=canvas.getContext('2d');ctx.drawImage(image,0,0,1290,2796);const maxWidth=1110,titleFamily=fonts[values.headline_font],supportFamily=fonts[values.supporting_font],titleWeight=weights[values.headline_font],supportWeight=values.supporting_font==='outfit'?'600':weights[values.supporting_font];let title=fitBlock(ctx,values.headline.toUpperCase(),maxWidth,4,values.headline_font==='amatic'?190:155,48,titleFamily,titleWeight),support=fitBlock(ctx,values.supporting_text,maxWidth,5,values.supporting_font==='amatic'?92:62,30,supportFamily,supportWeight);let titleLine=title.size*.92,supportLine=support.size*1.16,total=title.lines.length*titleLine+(support.lines.length?42+support.lines.length*supportLine:0),limit=values.text_position==='top'?650:570;while(total>limit&&title.size>42){title=fitBlock(ctx,values.headline.toUpperCase(),maxWidth,20,title.size-3,36,titleFamily,titleWeight);support=fitBlock(ctx,values.supporting_text,maxWidth,20,Math.max(27,support.size-2),24,supportFamily,supportWeight);titleLine=title.size*.92;supportLine=support.size*1.16;total=title.lines.length*titleLine+(support.lines.length?34+support.lines.length*supportLine:0)}let y=values.text_position==='top'?155:2796-145-total;ctx.textAlign='center';ctx.textBaseline='top';ctx.fillStyle=colors[values.headline_color];ctx.font=`${titleWeight} ${title.size}px "${titleFamily}"`;title.lines.forEach((line,index)=>ctx.fillText(line,645,y+index*titleLine));y+=title.lines.length*titleLine+34;ctx.fillStyle=colors[values.supporting_color];ctx.font=`${supportWeight} ${support.size}px "${supportFamily}"`;support.lines.forEach((line,index)=>ctx.fillText(line,645,y+index*supportLine));return canvas}
function persist(section){const values=sectionValues(section);if(section.dataset.artworkUrl)values._artworkUrl=section.dataset.artworkUrl;localStorage.setItem(`misery-screenshot-frame-${section.dataset.frame}`,JSON.stringify(values))}
function addSaved(saved){const grid=document.getElementById('savedGrid');grid.querySelector('.saved-empty')?.remove();const item=document.createElement('div');item.className='saved-item';item.innerHTML=`<img src="${saved.url}?v=${Date.now()}" alt="Saved Apple screenshot"><a href="${saved.url}" download="${saved.filename}">${saved.filename}</a>`;grid.prepend(item);document.getElementById('savedCount').textContent=`${grid.querySelectorAll('.saved-item').length} saved`}
document.querySelectorAll('.shot-frame').forEach(section=>{const form=section.querySelector('.shot-form'),status=section.querySelector('.shot-status'),artwork=section.querySelector('.shot-artwork'),empty=section.querySelector('.shot-empty'),saveButton=section.querySelector('.shot-save'),downloadButton=section.querySelector('.shot-download');try{const saved=JSON.parse(localStorage.getItem(`misery-screenshot-frame-${section.dataset.frame}`)||'{}');Object.entries(saved).forEach(([name,value])=>{if(name==='_artworkUrl'){section.dataset.artworkUrl=value;artwork.src=value;artwork.hidden=false;empty.hidden=true;saveButton.disabled=false;downloadButton.disabled=false;return}const field=form.elements.namedItem(name);if(field&&field.type!=='file')field.value=value})}catch{}syncPreview(section);form.querySelectorAll('input:not([type=file]),textarea,select').forEach(field=>field.addEventListener('input',()=>{syncPreview(section);persist(section)}));form.addEventListener('submit',async event=>{event.preventDefault();const button=form.querySelector('.shot-generate'),label=button.textContent;button.disabled=true;button.textContent='Gemini is generating artwork…';status.className='shot-status';status.textContent='Generating phone, people and rainbow background without marketing text…';try{const response=await fetch(generateUrl,{method:'POST',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf},body:new FormData(form)});if(!response.ok)return await jsonError(response);const payload=await response.json();section.dataset.artworkUrl=`${payload.url}?v=${Date.now()}`;artwork.src=section.dataset.artworkUrl;artwork.hidden=false;empty.hidden=true;saveButton.disabled=false;downloadButton.disabled=false;persist(section);status.textContent=`Artwork ready · ${payload.provider} · text remains editable`}catch(error){status.className='shot-status error';status.textContent=error.message||'Generation failed.'}finally{button.disabled=false;button.textContent=label}});downloadButton.addEventListener('click',async()=>{const label=downloadButton.textContent;downloadButton.disabled=true;downloadButton.textContent='Rendering…';try{const canvas=await compose(section),blob=await new Promise(resolve=>canvas.toBlob(resolve,'image/png'));if(!blob)throw new Error('PNG rendering failed.');const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=`misery-frame-${String(section.dataset.frame).padStart(2,'0')}.png`;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),1500)}catch(error){status.className='shot-status error';status.textContent=error.message}finally{downloadButton.disabled=false;downloadButton.textContent=label}});saveButton.addEventListener('click',async()=>{const label=saveButton.textContent;saveButton.disabled=true;saveButton.textContent='Saving…';try{const canvas=await compose(section),values=sectionValues(section),response=await fetch(saveUrl,{method:'POST',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf},body:JSON.stringify({...values,image_data:canvas.toDataURL('image/jpeg',.94)})});if(!response.ok)return await jsonError(response);const payload=await response.json();addSaved(payload);status.className='shot-status';status.textContent=`Saved permanently · ${payload.filename}`}catch(error){status.className='shot-status error';status.textContent=error.message||'Save failed.'}finally{saveButton.disabled=false;saveButton.textContent=label}})});
})();
</script>
